client_script:
frappe.web_form.after_load = function() {
  var doc = frappe.web_form.doc;
  if (doc && doc.name) {
    var refEl = document.createElement('div');
    refEl.innerHTML = '<div style="margin-bottom:12px;padding:8px 16px;background:#f1f8e9;color:#33691e;border-left:4px solid #8bc34a;border-radius:6px;display:inline-block;font-weight:700;margin-right:10px;font-size:14px;">Réf. Dossier : ' + doc.name + '</div>';
    var w = document.querySelector('.web-form-wrapper') || document.querySelector('.container');
    if (w) w.prepend(refEl);
  }
  var roles = (frappe.boot && frappe.boot.user && frappe.boot.user.roles) ? frappe.boot.user.roles : [];
  var state = (doc && (doc.workflow_state || doc.statut)) || 'Brouillon';
  var rules = {
    'signature_demandeur': { states: ['Brouillon'], roles: [] },
    'signature_chef': { states: ['En attente Chef'], roles: ['Chef Service','System Manager'] },
    'signature_dga': { states: ['En attente DAAF'], roles: ['DAAF','Purchase Manager','System Manager'] },
    'signature_dg': { states: ['En attente DG'], roles: ['Directeur Général','DG','System Manager'] }
  };
  var allSig = ['signature_demandeur','signature_chef','signature_dga','signature_dg'];
  allSig.forEach(function(f){ try{ frappe.web_form.set_df_property(f, 'read_only', 1); }catch(e){} });
  Object.keys(rules).forEach(function(field) {
    var rule = rules[field];
    var stateOk = rule.states.indexOf(state) !== -1;
    var roleOk = rule.roles.length === 0 || rule.roles.some(function(r){ return roles.indexOf(r) !== -1; });
    if (stateOk && roleOk) { try{ frappe.web_form.set_df_property(field, 'read_only', 0); }catch(e){} }
  });
  var montant = (doc && doc.montant_total) ? parseFloat(doc.montant_total) : 0;
  var urg = (doc && doc.urgence) || 'Normal';
  var urgent = urg !== 'Normal';
  var palierMsg, palierColor;
  if (montant > 15000000) { palierMsg = 'Palier 4 (> 15M XOF) : Appel d\u2019offre international 30j \u2014 Chef + DAAF + DG'; palierColor = '#6a1b9a'; }
  else if (montant > 2000000) { palierMsg = 'Palier 3 (2M\u201315M XOF) : Appel d\u2019offre national 2 sem. \u2014 Chef + DAAF + DG'; palierColor = '#c62828'; }
  else if (montant > 100000) { palierMsg = 'Palier 2 (100k\u20132M XOF) : 3 devis obligatoires \u2014 Chef + DAAF + DG'; palierColor = '#e65100'; }
  else if (urgent) { palierMsg = 'Palier 1 URGENT (\u2264 100k XOF) : Validation DG requise (proc. accélérée)'; palierColor = '#c62828'; }
  else { palierMsg = 'Palier 1 (\u2264 100k XOF) : Procédure simplifiée 72h \u2014 Chef + DAAF'; palierColor = '#1565c0'; }
  if (urgent) palierMsg += ' \u2014 \ud83d\udea8 ' + urg;
  if (doc && doc.statut) {
    var cm = {'Approuv\u00e9':'#2e7d32','Rejet\u00e9':'#c62828','Brouillon':'#757575'};
    var c = cm[doc.statut] || '#e65100';
    var el = document.createElement('div');
    el.innerHTML = '<div style="margin-bottom:8px;padding:8px 16px;background:'+c+';color:#fff;border-radius:6px;display:inline-block;font-weight:700;">\u00c9tat\u00a0: '+doc.statut+'</div>  <div style="margin-bottom:12px;padding:6px 14px;background:'+palierColor+';color:#fff;border-radius:6px;display:inline-block;font-size:0.85em;">'+palierMsg+'</div>';
    var w = document.querySelector('.web-form-wrapper') || document.querySelector('.container');
    if (w) w.prepend(el);
  }
};
frappe.web_form.on && frappe.web_form.on('urgence', function(){ setTimeout(function(){ try{ frappe.web_form.after_load(); }catch(e){} }, 100); });
frappe.web_form.on('load', function(){
  var doc = frappe.web_form.doc;
  if (doc && !doc.employee && frappe.session && frappe.session.user) {
    frappe.call({ method:'frappe.client.get_value', args:{ doctype:'Employee', filters:{ user_id: frappe.session.user, status:'Active' }, fieldname:['name','employee_name'] }, callback:function(r){ if(r.message){ frappe.web_form.set_value('employee', r.message.name); } } });
  }
});
